import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';

export default function Dashboard() {
  const [stats, setStats] = useState({ candidates: 0, templates: 0, transformations: 0 });
  const navigate = useNavigate();

  useEffect(() => {
    Promise.all([
      api.get('/candidates').catch(() => ({ data: [] })),
      api.get('/templates').catch(() => ({ data: [] })),
    ]).then(([cands, tmpls]) => {
      setStats({
        candidates: cands.data.length,
        templates: tmpls.data.length,
        transformations: 0,
      });
    });
  }, []);

  const cards = [
    { label: 'Profils actifs', value: stats.candidates, color: 'bg-blue-600', icon: '👤', action: () => navigate('/profiles') },
    { label: 'Templates disponibles', value: stats.templates, color: 'bg-green-600', icon: '📄', action: () => navigate('/templates') },
    { label: 'CV transformés', value: stats.transformations, color: 'bg-yellow-500', icon: '✨', action: () => navigate('/transformation') },
  ];

  return (
    <div className="p-8">
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-gray-900">Dashboard</h1>
        <p className="text-gray-500 mt-1">Bienvenue sur la plateforme RH Tritux</p>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        {cards.map((card) => (
          <button
            key={card.label}
            onClick={card.action}
            className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 hover:shadow-md transition-all text-left"
          >
            <div className={`w-12 h-12 ${card.color} rounded-xl flex items-center justify-center text-2xl mb-4`}>
              {card.icon}
            </div>
            <p className="text-3xl font-bold text-gray-900">{card.value}</p>
            <p className="text-gray-500 text-sm mt-1">{card.label}</p>
          </button>
        ))}
      </div>

      {/* Quick actions */}
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
        <h2 className="text-lg font-semibold text-gray-800 mb-4">Actions rapides</h2>
        <div className="flex flex-wrap gap-3">
          <button
            onClick={() => navigate('/profiles')}
            className="bg-blue-600 text-white px-5 py-2.5 rounded-lg text-sm font-medium hover:bg-blue-700 transition"
          >
            + Importer un CV
          </button>
          <button
            onClick={() => navigate('/templates')}
            className="bg-gray-100 text-gray-700 px-5 py-2.5 rounded-lg text-sm font-medium hover:bg-gray-200 transition"
          >
            Voir les templates
          </button>
          <button
            onClick={() => navigate('/transformation')}
            className="bg-gray-100 text-gray-700 px-5 py-2.5 rounded-lg text-sm font-medium hover:bg-gray-200 transition"
          >
            Transformer un CV
          </button>
        </div>
      </div>
    </div>
  );
}
